// friday13.cs — Friday the 13th in the proleptic Gregorian calendar
#:property InvariantGlobalization=false

// 1) Find the earliest Friday the 13th starting from 0001-01-01
var date = new DateTime(1, 1, 13); // start on the 13th of January, year 1
while (date.DayOfWeek != DayOfWeek.Friday)
    date = date.AddMonths(1);

Console.WriteLine($"Earliest Friday the 13th: {date:yyyy-MM-dd} ({date.DayOfWeek})");

// 2) Count Friday the 13ths in a full 400-year cycle (the Gregorian calendar repeats every 400 years)
int count = 0;
var start = new DateTime(1, 1, 13);
var end = new DateTime(401, 1, 1);

for (var d = start; d < end; d = d.AddMonths(1))
{
    if (d.DayOfWeek == DayOfWeek.Friday)
        count++;
}

Console.WriteLine($"Friday the 13ths in a 400-year cycle: {count}");
Console.WriteLine($"Average per year: {count / 400.0:F4}");

// 3) Bonus: breakdown by month
var byMonth = new int[12];
for (var d = start; d < end; d = d.AddMonths(1))
{
    if (d.DayOfWeek == DayOfWeek.Friday)
        byMonth[d.Month - 1]++;
}

Console.WriteLine("\nBreakdown by month:");
for (int m = 0; m < 12; m++)
    Console.WriteLine($"  {new DateTime(2000, m + 1, 1):MMMM,-12} {byMonth[m],3}");

